from beeai.events import EventListener

class IntentClassifier(EventListener):
    def on_user_message(self, message: str) -> str:
        intents = ['greeting', 'query', 'task', 'goodbye']
        # Granite classification
        intent = llm.classify(message, intents)

        if intent == 'query':
            return agent.run(message)  # RAG path
        elif intent == 'task':
            return agent.run(message, tools=True)
        return agent.run(message)

classifier = IntentClassifier()

