class VexToolGuard(EventListener):
    def on_tool_call(self, tool_call):
        # Verify tool parameters
        validation = vex.validate_tool_call(
            tool_name=tool_call.name,
            parameters=tool_call.args,
            allowed_tools=['search_knowledge_base'],
            session_context=agent.memory.get_context()
        )

        if not validation.safe:
            vex.log_security_event('tool_injection_attempt', tool_call)
            return {'error': 'Invalid tool usage detected'}

        # Execute validated tool
        result = tools.execute(tool_call.name, **tool_call.args)
        return {'result': result}

tool_guard = VexToolGuard()
EventBus.register('before_tool_call', tool_guard.on_tool_call)
